	groups, err := f.metricStore().GroupedHistory(args[0])
	if err != nil {
		return err
	}
	if cmd.Flags().Changed("json") {
		enc := json.NewEncoder(cmd.OutOrStdout())
		enc.SetIndent("", "  ")
		return enc.Encode(groups)
	}
	for _, group := range groups {
		unit := group.Unit
		if unit == "" {
